def sample_project(root=None, foldername=None, **kwds):
    if root is None:
        root = 'sample_project'
        if foldername:
            root = foldername
        # HACK: Using ``/dev/shm/`` for faster tests
        if os.name == 'posix':
            if os.path.isdir('/dev/shm') and os.access('/dev/shm', os.W_OK):
